--
-- Table structure for table `orders_order`
--

DROP TABLE IF EXISTS `orders_order`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `orders_order` (
  `id` bigint NOT NULL AUTO_INCREMENT,
  `price` decimal(10,2) NOT NULL,
  `status` varchar(20) COLLATE utf8mb4_unicode_ci NOT NULL,
  `effective_date` date NOT NULL,
  `notes` longtext COLLATE utf8mb4_unicode_ci,
  `created_at` datetime(6) NOT NULL,
  `updated_at` datetime(6) NOT NULL,
  `client_id` bigint NOT NULL,
  `courier_id` int DEFAULT NULL,
  `payment_method` varchar(20) COLLATE utf8mb4_unicode_ci NOT NULL,
  `inquantity` int unsigned NOT NULL,
  `outquantity` int unsigned NOT NULL,
  PRIMARY KEY (`id`),
  KEY `order_date_status_idx` (`effective_date`,`status`),
  KEY `order_client_date_idx` (`client_id`,`effective_date`),
  KEY `order_courier_date_idx` (`courier_id`,`effective_date`),
  KEY `order_status_payment_idx` (`status`,`payment_method`),
  KEY `order_created_idx` (`created_at` DESC),
  CONSTRAINT `orders_order_client_id_67117a15_fk_clients_client_id` FOREIGN KEY (`client_id`) REFERENCES `clients_client` (`id`),
  CONSTRAINT `orders_order_courier_id_80f94e0c_fk_auth_user_id` FOREIGN KEY (`courier_id`) REFERENCES `auth_user` (`id`),
  CONSTRAINT `orders_order_chk_1` CHECK ((`inquantity` >= 0)),
  CONSTRAINT `orders_order_chk_2` CHECK ((`outquantity` >= 0))
) ENGINE=InnoDB AUTO_INCREMENT=2295 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

